import React, { forwardRef, type PropsWithChildren } from "react";
import { ResponsiveElement, useSeparator } from "../../factory";
import type {IGridItemComponent, IStyleClasses} from "@lmb-it/kitsconcerto-types";

type IsolatedGridItem = Omit<IGridItemComponent, keyof IStyleClasses>

const GridItem = forwardRef<any, PropsWithChildren<IGridItemComponent>>((props, ref) => {
    const { cssProps, nativeProps } = useSeparator<IsolatedGridItem>(props);
    const { children, entering, exiting, ...rest } = nativeProps;

    return (
        <ResponsiveElement<IsolatedGridItem>
            ref={ref}
            entering={entering}
            exiting={exiting}
            nativeProps={rest}
            cssProps={cssProps}
        >
            {children}
        </ResponsiveElement>
    );
});

export default GridItem;
